// frontend/app/auth.js
// frontend/app/auth.js
import NextAuth from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";
import GithubProvider from "next-auth/providers/github";
import GoogleProvider from "next-auth/providers/google";
import axios from "axios";

export const authOptions = {
  providers: [
    CredentialsProvider({
      name: "Credentials",
      credentials: {
        emailOrphone: { label: "Email or Phone", type: "text" },
        password: { label: "Password", type: "password" },
      },
      async authorize(credentials) {
        try {
          const res = await axios.post("http://localhost:5000/api/login", {
            emailOrphone: credentials.emailOrphone,
            password: credentials.password
          });
          const user = res.data;
          if (res.status === 200 && user) {
            return user;
          }
          return null;
        } catch (error) {
          console.error("Credentials login error:", error.response?.data || error.message);
          return null;
        }
      }
    }),
    GithubProvider({
      clientId: process.env.GITHUB_CLIENT_ID,
      clientSecret: process.env.GITHUB_CLIENT_SECRET,
      profile(profile) {
        return {
          id: profile.id.toString(),
          name: profile.name || profile.login,
          email: profile.email,
          image: profile.avatar_url
        };
      }
    }),
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
      authorization: {
        params: {
          scope: "openid email profile https://www.googleapis.com/auth/user.phonenumbers.read"
        }
      },
      profile(profile) {
        return {
          id: profile.sub,
          name: profile.name,
          email: profile.email,
          image: profile.picture,
          phone: profile.phone_number || null
        };
      }
    })
  ],
  secret: process.env.AUTH_SECRET,
  session: { strategy: "jwt" },
  callbacks: {
    async signIn({ user, account, profile }) {
      try {
        if (account.provider === "github" || account.provider === "google") {
          const res = await axios.post("http://localhost:5000/api/oauthsignup", {
            email: user.email,
            username: user.name || profile.name || profile.login,
            phone: user.phone || '',
            provider: account.provider,
            providerId: user.id
          });
          const backendUser = res.data.user;
          user.id = backendUser.id;
          user.role = backendUser.role;
          user.username = backendUser.username;
          user.email = backendUser.email;
          user.phone = backendUser.phone;
          user.instagram = backendUser.instagram;
          user.youtube = backendUser.youtube;
          user.facebook = backendUser.facebook;
          return true;
        }
        return true;
      } catch (error) {
        console.error("SignIn callback error:", error.response?.data || error.message);
        return false;
      }
    },
    async jwt({ token, user }) {
      if (user) {
        token.id = user.id;
        token.email = user.email;
        token.role = user.role || "user";
        token.username = user.username;
        token.phone = user.phone;
        token.instagram = user.instagram;
        token.youtube = user.youtube;
        token.facebook = user.facebook;
      }
      return token;
    },
    async session({ session, token }) {
      session.user.id = token.id;
      session.user.email = token.email;
      session.user.role = token.role;
      session.user.username = token.username;
      session.user.phone = token.phone;
      session.user.instagram = token.instagram;
      session.user.youtube = token.youtube;
      session.user.facebook = token.facebook;
      return session;
    },
    async redirect({ url, baseUrl }) {
      if (url.includes("callback")) {
        const session = await authOptions.session({ token: await authOptions.jwt({ user: null }) });
        if (session?.user?.role === "admin") {
          return `${baseUrl}/admindashboard`;
        }
        return `${baseUrl}/homepage`;
      }
      return url;
    }
  }
};

export const { handlers, signIn, signOut, auth } = NextAuth(authOptions);